#!/usr/bin/env bash
# bdd.sh — 求美者面诊与需求挖掘（含 BDD / 容貌焦虑筛查） SOP walkthrough for 医疗美容.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="医疗美容"
WORKFLOW="求美者面诊与需求挖掘（含 BDD / 容貌焦虑筛查）"

usage() {
  cat <<EOF
bdd.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./bdd.sh             # interactive
  ./bdd.sh --dry-run
  ./bdd.sh --json
  ./bdd.sh --explain
  ./bdd.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "求美者面诊与需求挖掘（含 BDD / 容貌焦虑筛查）" 工作流。

一句话: 从「一个带着模糊变美诉求来的人」到「一份主诉清晰、禁忌排除、预期对齐、并明确『该做 / 该劝退』的医疗诊断」。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 医美的第一性是医疗，不是消费: 医疗美容首先是外科与皮肤科的**医疗行为**（可致盲、致残、致死），不是快消品；任何决策的第一约束是安全与合规，不是美学最大化或转化率。
  • 先安全后审美：风险分层判断: 资深人的核心能力不是「打得漂亮」，而是**在安全处提效、在危险处零妥协**——知道哪一步能省、哪一步一步都不能省。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**接诊与建档**：核对身份、建电子病历、采集主诉（「你最想改善哪里」），区分「求美者」诉求 vs 销售报价（这是医疗诊断不是聊价）。 evidence: [T03-S001]"
  "**既往史与禁忌排查**：妊娠哺乳、过敏史、凝血/免疫疾病、感染、瘢痕体质、近期填充/线材史、用药史；排禁忌证。"
  "**解剖与皮肤评估**：面部分区视诊触诊 + Fitzpatrick 皮肤分型（决定光电参数与色沉风险）；可用 VISIA 客观量化。 evidence: [T03-S014]"
  "**动机与预期对话**：问「为什么现在想做 / 想达到什么效果 / 看过谁的样子」；把不切实际预期（「变成某明星」「一次解决全部」）拉回现实。"
  "**BDD / 容貌焦虑初筛**：诉求异常强烈、反复修整、对微小瑕疵病理性关注、多次他院不满意 → 警惕体象障碍，触发**劝退**而非升单。 evidence: [T03-S002]"
  "**给出方向或劝退**：适应证清晰→进入方案设计；无适应证/禁忌/BDD→诚实劝退（「这个不必做 / 你现在不适合做」）。"
)
declare -a FAILURE_MODES=(
  "**把面诊当销售而非诊断**：触发原因—咨询师主导、以转化率为 KPI。避免：医生主导、医疗诊断框架先行，把面诊当成做不做的医学判断。"
  "**跳过 BDD 筛查给焦虑型客户做项目**：会导致反复修整 + 投诉 + 成瘾。actionable：诉求异常强烈/反复修整/多次他院不满意=触发劝退而非排期。"
  "**预期不对齐就开做**：actionable—不要在求美者说「变成某明星/一次全解决」时直接排期，先用 VISIA/3D 把可达成范围讲清并书面记录，否则术后落差几乎必投诉。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "bdd-walkthrough"
fi
